import { useEffect, useState } from "react";
import NavbarComponent from "../../components/Navbar";
import { useNavigate } from "react-router-dom";
import { StudentAuthApi, StudentRoomDetails } from "../../apis/student";
import { ParentAuthApi, ParentRoomDetails } from "../../apis/parent";


const MyRoomPage = () => {
    // navigate
    const navigate = useNavigate()

    // get current admin ( hostel or parent or student)
    const admin = localStorage.getItem("admin")

    // states
    const [myRoom, setMyRoom] = useState({})
    const [hostelId, setHostelId] = useState("")
    const [roomNo, setRoomNo] = useState("")

    // use effect for login or not checking
    useEffect(() => {
        async function auth() {
            if (admin === "student") {
                const token = localStorage.getItem("studenttoken")
                if (token) {
                    const auth = await StudentAuthApi(token)
                    if (!auth || auth.status === "failed" || !auth.auth) {
                        navigate("/login")
                    }
                    setHostelId(auth?.student_details?.hostel_id)
                    setRoomNo(auth?.student_details?.room_no)
                }
            } else {
                const token = localStorage.getItem("parenttoken")
                if (token) {
                    const auth = await ParentAuthApi(token)
                    if (!auth || auth.status === "failed" || !auth.auth) {
                        navigate("/login")
                    }
                    setHostelId(auth?.parent_details?.hostel_id)
                    setRoomNo(auth?.student?.room_no)
                }
            }
        }
        auth()
    }, []);

    // use effect fetching my room details
    useEffect(() => {
        async function fetchData() {
            if (hostelId && roomNo) {
                if (admin === "student") {
                    const token = localStorage.getItem("studenttoken")
                    const response = await StudentRoomDetails(token, hostelId, roomNo)
                    if (response && response.status === "success") {
                        setMyRoom(response.room)
                    } else {
                        alert(response?.message)
                    }
                } else {
                    const token = localStorage.getItem("parenttoken")
                    console.log(token);
                    const response = await ParentRoomDetails(token, hostelId, roomNo)
                    if (response && response.status === "success") {
                        setMyRoom(response.room)
                    } else {
                        alert(response?.message)
                    }
                }
            }
        }
        fetchData()
    }, [hostelId, roomNo]);

    // return
    return (
        <>
            <NavbarComponent now={'home'} />
            <div className="w-auto min-h-screen px-3 pt-16 bg-[#1B263B]">
                <div className="w-full min-h-screen rounded-lg px-5 py-5 mt-3 bg-gray-400">
                    <div className="w-full p-5">
                    <div className="flex flex-row border p-4 rounded-lg shadow-xl shadow-inner bg-gray-100">
                        <div className="w-full">
                            <h1 className="text-xl text-center font-extrabold">Room No - {myRoom?.room_no}</h1>
                            <h1 className="text-lg text-center font-bold">({myRoom?.room_type})</h1>
                        </div>
                        <div className="w-full space-x-10">
                            <h1 className="text-md font-semibold">Room Capacity - {myRoom?.capacity}</h1>
                        </div>
                    </div>
                        {/* My room details */}
                        {/* <div className="grid grid-cols-1 md:grid-cols-1 lg:grid-cols-2 gap-5">
                            {myRoom.occuppants.map((item, index) => (
                                <div key={index} className="flex flex-row border p-4 rounded-lg shadow-xl shadow-inner bg-gray-100">
                                    <div className="ml-5 w-full">
                                        <h1 className="text-xl font-extrabold text-center">
                                            {item.day}
                                        </h1>
                                        <h1 className="text-md font-bold mt-2">
                                            Breakfast - <span className="font-semibold capitalize">{item?.items[0]?.dishes}</span>
                                        </h1>
                                        <h1 className="text-md font-bold mt-1">
                                            Lunch - <span className="font-semibold capitalize">{item?.items[1]?.dishes}</span>
                                        </h1>
                                        <h1 className="text-md font-bold mt-1">
                                            Dinner - <span className="font-semibold capitalize">{item?.items[2]?.dishes}</span>
                                        </h1>
                                    </div>
                                </div>
                            ))}
                        </div> */}
                    </div>
                </div>
            </div>
        </>
    );
}

export default MyRoomPage;
